let input = {};
try {
  input = $('Execute Workflow Trigger').first().json || {};
} catch (e) {
  input = {};
}
const defaults = {
  systemPrompt: 'You are a professional business consultant and writer for IntraWeb Technologies. You write in a direct, clear, and professional tone. Avoid filler and generic language. Tailor responses to the context provided.',
  userPrompt: 'Write a 2–3 sentence introduction for a consulting proposal. The client is a local service business (e.g., HVAC or plumbing) looking to automate their operations. Mention the value of custom-built systems over generic software.'
};
return [{
  json: {
    systemPrompt: (input.systemPrompt && input.systemPrompt.trim()) ? input.systemPrompt : defaults.systemPrompt,
    userPrompt: (input.userPrompt && input.userPrompt.trim()) ? input.userPrompt : defaults.userPrompt,
    maxTokens: Number(input.maxTokens) || 2048
  }
}];

const response = $('Call Claude API').first().json;
if (response.error) {
  return [{
    json: {
      success: false,
      data: null,
      error: typeof response.error === 'object' ? JSON.stringify(response.error) : String(response.error),
    },
  }];
}
let text = '';
const blocks = response.content || [];
for (const b of blocks) {
  if (b && typeof b.text === 'string') {
    text += b.text;
  }
}
text = text.trim();
if (!text) {
  return [{
    json: {
      success: false,
      data: null,
      error: 'Claude returned no text (check model name, API key, and account access).',
    },
  }];
}
return [{ json: { success: true, data: { text }, error: null } }];

const item = $('Call Claude API').first();
const j = item.json || {};
let msg = '';
if (j.error && typeof j.error === 'object') {
  msg = j.error.message || JSON.stringify(j.error);
} else if (typeof j.error === 'string') {
  msg = j.error;
} else if (j.message) {
  msg = j.message;
} else if (j.type === 'error') {
  msg = j.error?.message || JSON.stringify(j);
} else {
  msg = 'HTTP request failed (check Anthropic API credential and API key in n8n credentials)';
}
return [{
  json: {
    success: false,
    data: null,
    error: `Claude API call failed: ${String(msg).substring(0, 400)}`
  }
}];

